  1→import { useEffect, useState } from 'react';
  2→import { getBookmarks } from '../../../API/Api';
  3→import { useAuth } from '../../Context/useAuth';
  4→import './bookmarks.css';
  5→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  6→import CalculateText from '../HomePage/postCards/calculateReadingTime';
  7→import { MoonLoader } from 'react-spinners';
  8→import { motion, AnimatePresence } from 'framer-motion';
  9→import { handleCLickContent, handleClickProfile } from '../../../helpers/handleClicks';
 10→import { useNavigate } from 'react-router-dom';
 11→import { useInView } from 'react-intersection-observer';
 12→import { useRef } from 'react';
 13→import VerifiedBadge from '../Badge/VerifiedBadge';
 14→import formatPostDate from '../../../helpers/formatDateString';
 15→import { handleImageFallback } from '../../utils/handleImageFallback';
 16→
 17→const Bookmarks = () =>{
 18→    const {user, session} = useAuth();
 19→    const userId = user?.userData?.[0].id
 20→    const navigate = useNavigate();
 21→
 22→    const {ref: inviewRef, inView} = useInView({
 23→        threshold: 0.2
 24→    });
 25→    const timeOutRef = useRef();
 26→    const scrollToTop = useRef();
 27→    const modalRef = useRef(null);
 28→
 29→    const [bookmarkIdSettings, setBookmarkIdSettings] = useState('');
 30→    const [showHeaders, setShowHeaders] = useState(true);
 31→
 32→    const handleclickUserProfile = handleClickProfile(navigate);
 33→
 34→    const handleClickBookmarkSettings = (e, journalId) => {
 35→        e.stopPropagation();
 36→        setBookmarkIdSettings(journalId === bookmarkIdSettings ? null : journalId)
 37→    }
 38→
 39→    const handleBackLocation = (e) =>{
 40→        e.stopPropagation();
 41→        window.history.back();
 42→    }
 43→
 44→    const handleClick = handleCLickContent(navigate);
 45→
 46→    const queryClient = useQueryClient();
 47→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
 48→        queryKey: ['getBookmarks', userId],
 49→        queryFn: ({queryKey, pageParam = null}) => getBookmarks(pageParam, 5, queryKey[1], session?.access_token),
 50→        getNextPageParam: (lastPage) => {
 51→            if(lastPage?.hasMore){
 52→                const lastBookmark = lastPage.bookmarks[lastPage?.bookmarks?.length - 1];
 53→                return new Date(lastBookmark.created_at).toISOString();
 54→            } else {
 55→                return undefined;
 56→            }
 57→        },
 58→        enabled: !!userId,
 59→        refetchOnWindowFocus: false,
 60→        staleTime: 1000 * 60 * 5,
 61→    })
 62→
 63→    useEffect(() =>{
 64→        if(inView && hasNextPage && !isFetchingNextPage){
 65→            fetchNextPage();
 66→        }
 67→
 68→    }, [hasNextPage, fetchNextPage, isFetchingNextPage, inView])
 69→
 70→    useEffect(() =>{
 71→        const scroll = () =>{
 72→            setShowHeaders(false)
 73→            if(timeOutRef.current){
 74→                clearTimeout(timeOutRef.current)
 75→            }
 76→            timeOutRef.current = setTimeout(() =>{
 77→                setShowHeaders(true)
 78→            }, 500)
 79→        }
 80→
 81→        document.addEventListener('scroll', scroll, true)
 82→        return () =>{
 83→             if(timeOutRef.current){
 84→                clearTimeout(timeOutRef.current);
 85→            }
 86→            document.removeEventListener('scroll', scroll, true)
 87→        }
 88→    }, [])
 89→
 90→    useEffect(() =>{
 91→        // console.log(data)
 92→    }, [data])
 93→
 94→    useEffect(() => {
 95→        const handleClickOutside = (e) =>{
 96→            if(modalRef.current && !modalRef.current.contains(e.target)){
 97→                setBookmarkIdSettings(null)
 98→            }
 99→        }
100→        window.addEventListener('click', handleClickOutside)
101→        return() => {
102→            window.removeEventListener('click', handleClickOutside)
103→        }
104→    }, [])
105→
106→    const journals = data?.pages?.flatMap((journal) => journal.bookmarks|| []);
107→    const totalBookmarks = data?.pages?.flatMap((journal) => journal.totalBookmarks)
108→
109→    useEffect(() => {
110→        if(!isLoading && scrollToTop.current){
111→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
112→        }
113→    }, [isLoading])
114→
115→    if(isLoading){
116→        return(
117→            <div className='bookmark-loading-container'>
118→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
119→            </div>
120→        )
121→    }
122→    if(journals?.length === 0){
123→        return(
124→            <div className='bookmark-parent-container'>
125→                <p>No bookmarks available</p>
126→            </div>
127→        )
128→    }
129→
130→
131→    return(
132→        <>
133→        <div ref={scrollToTop}/>
134→        <AnimatePresence>
135→        {showHeaders && (
136→            <motion.div
137→            className='bookmarks-header'
138→            initial={{opacity: 0}}
139→            animate={{opacity: 1, transition:{ type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
140→            exit={{opacity:0, y: -20, transition:{duration: 0.2, ease: 'easeInOut'}}}
141→            >
142→                <div onClick={(e) => handleBackLocation(e)} className='back-button'>
143→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z"/></svg>
144→                </div>
145→
146→                <p className='bookmarks-header-text'>Bookmarks <span className='bookmarks-header-count'>({totalBookmarks})</span></p>
147→            </motion.div>
148→        )}
149→        </AnimatePresence>
150→
151→        <div className='bookmark-parent-container'>
152→            {journals?.map((journal, index) => {
153→                const previewText = journal.journals.preview_text || '';
154→                const thumbnail = journal.journals.thumbnail_url || null;
155→                return(
156→                    <motion.div
157→                        className='bookmark-card'
158→                        key={journal.journals.id || index}
159→                    >
160→
161→                        {thumbnail && (
162→                            <img
163→                                className="bookmark-card-image-banner"
164→                                src={thumbnail}
165→                                alt={journal?.journals?.title ? `${journal.journals.title} cover image` : "Bookmarked post cover image"}
166→                                loading="lazy"
167→                                onError={handleImageFallback}
168→                                onClick={(e) => handleClick(
169→                                    e,
170→                                    null,
171→                                    '',
172→                                    journal.journals.title,
173→                                    journal.journals.user_id,
174→                                    journal.journals.users.name,
175→                                    journal.journals.users.image_url,
176→                                    journal.journals.created_at,
177→                                    journal.journals.id,
178→                                    journal.has_liked,
179→                                    journal.journals.comment_count[0]?.count,
180→                                    journal.has_bookmarked,
181→                                    journal.journals.like_count?.[0]?.count,
182→                                    journal.journals.bookmark_count?.[0]?.count,
183→                                    journal.journals.users.badge
184→                                )}
185→                            />
186→                        )}
187→
188→                        <div className="card-content">
189→                            <div onClick={(e) => handleClick(
190→                                e,
191→                                null,
192→                                '',
193→                                journal.journals.title,
194→                                journal.journals.user_id,
195→                                journal.journals.users.name,
196→                                journal.journals.users.image_url,
197→                                journal.journals.created_at,
198→                                journal.journals.id,
199→                                journal.has_liked,
200→                                journal.journals.comment_count[0]?.count,
201→                                journal.has_bookmarked,
202→                                journal.journals.like_count?.[0]?.count,
203→                                journal.journals.bookmark_count?.[0]?.count,
204→                                journal.journals.users.badge
205→                            )}
206→                                className="content-container">
207→
208→                                <div className='feed-text-content-container'>
209→                                    <div className='feed-title-content'>
210→                                        <h2 className="feed-title">{journal.journals.title.length > 55 ? `${journal.journals.title.substring(0, 55)}...` : journal.journals.title}</h2>
211→                                    </div>
212→                                    <p className="feed-text-content">{previewText}</p>
213→                                </div>
214→                            </div>
215→                        </div>
216→
217→                        <div className="bookmark-card-footer">
218→                            <div className='user-info-child-container'>
219→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className={`user-avatar-container ${journal?.journals?.users?.badge === 'legend' ? 'avatar-ring-legend' : journal?.journals?.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
220→                                    <img loading='lazy' src={journal?.journals?.users?.image_url || '/assets/profile.jpg'} className="user-info-avatar" alt={`${journal?.journals?.users?.name || "User"} profile picture`} />
221→                                </div>
222→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className="user-name-container">
223→                                    <p className="user-newsfeed-name">{journal?.journals?.users?.name}</p>
224→                                    <VerifiedBadge badge={journal?.journals?.users?.badge} size={14} />
225→                                </div>
226→                                <div className="name-info-separator">•</div>
227→                                <p className="user-post-date">{formatPostDate(journal.created_at)}</p>
228→                            </div>
229→
230→                            <div className="bookmark-card-footer-right">
231→                                <div className="reading-time-container">
232→                                    <p className="reading-time-text">{CalculateText(previewText)}</p>
233→                                </div>
234→
235→                                <div className="user-post-settings">
236→                                    <svg onClick={(e) => handleClickBookmarkSettings(e, journal.journals.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
237→                                    {bookmarkIdSettings === journal.journals.id && (
238→                                        <motion.div
239→                                        initial={{opacity:0 ,scale:0}}
240→                                        animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
241→                                        exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
242→                                        ref={modalRef}
243→                                        className="setting-modal"
244→                                        >
245→                                            <p>{journal.journals.title}</p>
246→                                        </motion.div>
247→                                    )}
248→                                </div>
249→                            </div>
250→                        </div>
251→
252→                    </motion.div>
253→                )
254→            })}
255→            <div ref={inviewRef} className='inview-container'>
256→                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
257→            </div>
258→        </div>
259→        </>
260→    )
261→}
262→export default Bookmarks;
