 1→import formatPostDate from "../../../../helpers/formatDateString";
 2→import { handleImageFallback } from "../../../utils/handleImageFallback";
 3→import "./interestSections.css";
 4→
 5→const InterestSections = ({ sections, onPostClick }) => {
 6→    if (!sections || sections.length === 0) return null;
 7→
 8→    return (
 9→        <div className="interest-sections">
10→            {sections.map((section) => (
11→                <div key={section.interest} className="interest-section">
12→                    <div className="interest-section-header">
13→                        <span className="interest-section-title">
14→                            Trending in {section.interest}
15→                        </span>
16→                    </div>
17→                    <div className="interest-section-scroll">
18→                        {section.posts.map((post) => {
19→                            const thumbnail = post.thumbnail_url || null;
20→                            const excerpt = post.preview_text || '';
21→                            const title = post.title || 'Untitled';
22→                            const displayTitle = title.length > 50 ? title.slice(0, 50) + '...' : title;
23→
24→                            return (
25→                                <div
26→                                    key={post.id}
27→                                    className="interest-card"
28→                                    onClick={() => onPostClick(post.id)}
29→                                    role="button"
